ss->module,                    'profile' => $access->profile,                    'location_id' => $access->location_id,                    'location_name' => optional($access->location)->name,                ];            })->values(),        ];    })->values();@endphp</div><script>    window.accessControlUsers = {{ Illuminate\Support\Js::from($accessControlUsers) }};</script><script>    window.accessControlDivisions = {{ Illuminate\Support\Js::from($accessControlDivisions) }};</script><script>function openNewUserModal(){    document        .getElementById('newUserModal')        .classList        .add('active');}function closeNewUserModal(){    document        .getElementById('newUserModal')        .classList        .remove('active');}</script><script>lucide.createIcons();</script><script>document.addEventListener('DOMContentLoaded', function () {    const divisionSelect = document.getElementById('divisionSelect');    const locationSelect = document.getElementById('locationSelect');    if (!divisionSelect || !locationSelect) {        return;    }    divisionSelect.addEventListener('change', function () {        const divisionId = String(this.value);        locationSelect.innerHTML = '';        const defaultOption = document.createElement('option');        defaultOption.value = '';        defaultOption.textContent = 'Todas unidades';        locationSelect.appendChild(defaultOption);        const divisions = window.accessControlDivisions || [];        const selectedDivision = divisions.find(function (division) {            return String(division.id) === divisionId;        });        if (!selectedDivision || !selectedDivision.locations) {            return;        }        selectedDivision.locations.forEach(function (location) {            const option = document.createElement('option');            option.value = location.id;            option.textContent = location.name;            locationSelect.appendChild(option);        });    });});</script><script>let accessIndex = 0;function getSelectText(select) {    if (!select || !select.options || select.selectedIndex < 0) {        return '';    }    return select.options[select.selectedIndex].text;}function addAccess() {    const divisionSelect = document.getElementById('divisionSelect');    const moduleSelect = document.getElementById('moduleSelect');    const profileSelect = document.getElementById('profileSelect');    const locationSelect = document.getElementById('locationSelect');    const accessList = document.getElementById('accessList');    if (!divisionSelect || !moduleSelect || !profileSelect || !locationSelect || !accessList) {        return;    }    const divisionId = divisionSelect.value;    const module = moduleSelect.value;    const profile = profileSelect.value;    const locationId = locationSelect.value;    if (!divisionId) {        alert('Selecione uma divisão antes de adicionar o acesso.');        return;    }    if (!module) {        alert('Selecione um módulo.');        return;    }    if (!profile) {        alert('Selecione um perfil.');        return;    }    const duplicate = accessList.querySelector(        `[data-division-id="${divisionId}"][data-module="${module}"][data-profile="${profile}"][data-location-id="${locationId}"]`    );    if (duplicate) {        alert('Esse acesso já foi adicionado.');        return;    }    const emptyState = accessList.querySelector('.chm-empty-access');    if (emptyState) {        emptyState.remove();    }    const divisionName = getSelectText(divisionSelect);    const moduleName = getSelectText(moduleSelect);    const profileName = getSelectText(profileSelect);    const locationName = locationId ? getSelectText(locationSelect) : 'Todas unidades';    const item = document.createElement('div');    item.className = 'access-item';    item.dataset.divisionId = divisionId;    item.dataset.module = module;    item.dataset.profile = profile;    item.dataset.locationId = locationId;    item.innerHTML = `        <input type="hidden" name="accesses[${accessIndex}][division_id]" value="${divisionId}">        <input type="hidden" name="accesses[${accessIndex}][module]" value="${module}">        <input type="hidden" name="accesses[${accessIndex}][profile]" value="${profile}">        <input type="hidden" name="accesses[${accessIndex}][location_id]" value="${locationId}">        <span class="access-badge">${divisionName}</span>        <span class="access-badge">${moduleName}</span>        <span class="access-badge">${profileName}</span>        <span class="access-badge">${locationName}</span>        <button type="button" onclick="removeAccess(this)">            <i data-lucide="x"></i>        </button>    `;    accessList.appendChild(item);    accessIndex++;    if (window.lucide) {        lucide.createIcons();    }}function removeAccess(button) {    const item = button.closest('.access-item');    const accessList = document.getElementById('accessList');    if (item) {        item.remove();    }    if (accessList && accessList.querySelectorAll('.access-item').length === 0) {        accessList.innerHTML = `            <div class="chm-empty-access">                <i data-lucide="layers-3"></i>                <strong>                    Nenhum acesso adicionado                </strong>                <span>                    Selecione os dados acima e clique em adicionar acesso.                </span>            </div>        `;        if (window.lucide) {            lucide.createIcons();        }    }}</script><script>let editAccessIndex = 0;const moduleLabels = {    fleet: 'Frota',};const profileLabels = {    driver: 'Motorista',    mechanic: 'Mecânico',    supervisor: 'Supervisor',    manager: 'Gestor',};function openEditUserModal(userId){    const users = window.accessControlUsers || [];    const user = users.find(function (item) {        return Number(item.id) === Number(userId);    });    if (!user) {        return;    }    editAccessIndex = 0;    const form = document.getElementById('editUserForm');    form.action = `/access-control/${user.id}`;    document.getElementById('editUserName').value = user.name || '';    document.getElementById('editUserEmail').value = user.email || '';    document.getElementById('editUserPassword').value = '';    document.getElementById('editUserActive').checked = !!user.active;        const accessList = document.getElementById('editAccessList');    accessList.innerHTML = '';    if (!user.accesses || user.accesses.length === 0) {        renderEditEmptyState();    } else {        user.accesses.forEach(function (access) {            appendEditAccessItem({                division_id: access.division_id,                division_name: access.division_name,                module: access.module,                module_name: moduleLabels[access.module] || access.module,                profile: access.profile,                profile_name: profileLabels[access.profile] || access.profile,                location_id: access.location_id || '',                location_name: access.location_name || 'Todas unidades',            });        });    }    document        .getElementById('editUserModal')        .classList        .add('active');    if (window.lucide) {        lucide.createIcons();    }}function closeEditUserModal(){    document        .getElementById('editUserModal')        .classList        .remove('active');}function renderEditEmptyState(){    const accessList = document.getElementById('editAccessList');    accessList.innerHTML = `        <div class="chm-empty-access">            <i data-lucide="layers-3"></i>            <strong>                Nenhuma permissão vinculada            </strong>            <span>                Adicione pelo menos uma permissão antes de salvar.            </span>        </div>    `;    if (window.lucide) {        lucide.createIcons();    }}function addEditAccess(){    const divisionSelect = document.getElementById('editDivisionSelect');    const moduleSelect = document.getElementById('editModuleSelect');    const profileSelect = document.getElementById('editProfileSelect');    const locationSelect = document.getElementById('editLocationSelect');    const accessList = document.getElementById('editAccessList');    const divisionId = divisionSelect.value;    const module = moduleSelect.value;    const profile = profileSelect.value;    const locationId = locationSelect.value;    if (!divisionId) {        alert('Selecione uma divisão.');        return;    }    const duplicate = accessList.querySelector(        `[data-division-id="${divisionId}"][data-module="${module}"][data-profile="${profile}"][data-location-id="${locationId}"]`    );    if (duplicate) {        alert('Esse acesso já foi adicionado.');        return;    }    const emptyState = accessList.querySelector('.chm-empty-access');    if (emptyState) {        emptyState.remove();    }    appendEditAccessItem({        division_id: divisionId,        division_name: getSelectText(divisionSelect),        module: module,        module_name: getSelectText(moduleSelect),        profile: profile,        profile_name: getSelectText(profileSelect),        location_id: locationId,        location_name: locationId ? getSelectText(locationSelect) : 'Todas unidades',    });}function appendEditAccessItem(access){    const accessList = document.getElementById('editAccessList');    const item = document.createElement('div');    item.className = 'access-item';    item.dataset.divisionId = access.division_id;    item.dataset.module = access.module;    item.dataset.profile = access.profile;    item.dataset.locationId = access.location_id || '';    item.innerHTML = `        <input type="hidden" name="accesses[${editAccessIndex}][division_id]" value="${access.division_id}">        <input type="hidden" name="accesses[${editAccessIndex}][module]" value="${access.module}">        <input type="hidden" name="accesses[${editAccessIndex}][profile]" value="${access.profile}">        <input type="hidden" name="accesses[${editAccessIndex}][location_id]" value="${access.location_id || ''}">        <span class="access-badge">${access.division_name || 'Divisão'}</span>        <span class="access-badge">${access.module_name || access.module}</span>        <span class="access-badge">${access.profile_name || access.profile}</span>        <span class="access-badge">${access.location_name || 'Todas unidades'}</span>        <button type="button" onclick="removeEditAccess(this)">            <i data-lucide="x"></i>        </button>    `;    accessList.appendChild(item);    editAccessIndex++;    if (window.lucide) {        lucide.createIcons();    }}function removeEditAccess(button){    const item = button.closest('.access-item');    const accessList = document.getElementById('editAccessList');    if (item) {        item.remove();    }    if (accessList && accessList.querySelectorAll('.access-item').length === 0) {        renderEditEmptyState();    }}document.addEventListener('DOMContentLoaded', function () {    const editDivisionSelect = document.getElementById('editDivisionSelect');    const editLocationSelect = document.getElementById('editLocationSelect');    if (!editDivisionSelect || !editLocationSelect) {        return;    }    editDivisionSelect.addEventListener('change', function () {        const divisionId = String(this.value);        editLocationSelect.innerHTML = '';        const defaultOption = document.createElement('option');        defaultOption.value = '';        defaultOption.textContent = 'Todas unidades';        editLocationSelect.appendChild(defaultOption);        const divisions = window.accessControlDivisions || [];        const selectedDivision = divisions.find(function (division) {            return String(division.id) === divisionId;        });        if (!selectedDivision || !selectedDivision.locations) {            return;        }        selectedDivision.locations.forEach(function (location) {            const option = document.createElement('option');            option.value = location.id;            option.textContent = location.name;            editLocationSelect.appendChild(option);        });    });});</script>@endsection